export interface Chapter {
  id: string;
  title: string;
  content: string;
  createdAt: Date;
  updatedAt: Date;
}

export interface Story {
  id: string;
  title: string;
  author: string;
  chapters: Chapter[];
  createdAt: Date;
  updatedAt: Date;
}

export interface ExportOptions {
  format: 'json' | 'markdown' | 'html';
  includeMetadata: boolean;
  chapterIds?: string[];
}

export interface ExportResult {
  success: boolean;
  data: string;
  format: string;
  exportedAt: Date;
}

/**
 * Export chapters from a story in various formats
 * @param story - The story containing chapters to export
 * @param options - Export configuration options
 * @returns ExportResult with the exported data
 */
export function exportChapters(story: Story, options: ExportOptions): ExportResult {
  const chaptersToExport = options.chapterIds
    ? story.chapters.filter(ch => options.chapterIds!.includes(ch.id))
    : story.chapters;

  let data: string;

  switch (options.format) {
    case 'json':
      data = exportAsJson(chaptersToExport, story, options.includeMetadata);
      break;
    case 'markdown':
      data = exportAsMarkdown(chaptersToExport, story, options.includeMetadata);
      break;
    case 'html':
      data = exportAsHtml(chaptersToExport, story, options.includeMetadata);
      break;
    default:
      throw new Error(`Unsupported export format: ${options.format}`);
  }

  return {
    success: true,
    data,
    format: options.format,
    exportedAt: new Date(),
  };
}

function exportAsJson(chapters: Chapter[], story: Story, includeMetadata: boolean): string {
  const exportData = includeMetadata
    ? { storyTitle: story.title, author: story.author, chapters }
    : { chapters };
  return JSON.stringify(exportData, null, 2);
}

function exportAsMarkdown(chapters: Chapter[], story: Story, includeMetadata: boolean): string {
  let md = '';
  if (includeMetadata) {
    md += `# ${story.title}\\n\\nBy ${story.author}\\n\\n---\\n\\n`;
  }
  chapters.forEach((chapter, index) => {
    md += `## ${chapter.title}\\n\\n${chapter.content}\\n\\n`;
    if (index < chapters.length - 1) md += '---\\n\\n';
  });
  return md;
}

function exportAsHtml(chapters: Chapter[], story: Story, includeMetadata: boolean): string {
  let html = '<!DOCTYPE html>\\n<html>\\n<head>\\n<meta charset="UTF-8">\\n';
  html += `<title>${story.title}</title>\\n</head>\\n<body>\\n`;
  if (includeMetadata) {
    html += `<h1>${story.title}</h1>\\n<p class="author">By ${story.author}</p>\\n<hr>\\n`;
  }
  chapters.forEach(chapter => {
    html += `<article>\\n<h2>${chapter.title}</h2>\\n<div class="content">${chapter.content}</div>\\n</article>\\n`;
  });
  html += '</body>\\n</html>';
  return html;
}

export default { exportChapters };
'''

